+
+        // ------------ Long -------------
+        ops.add(Expression.make(INTS,  "Long.bitCount(", LONGS, ")"));
+        ops.add(Expression.make(INTS,  "Long.compare(", LONGS, ", ", LONGS, ")"));
+        ops.add(Expression.make(INTS,  "Long.compareUnsigned(", LONGS, ", ", LONGS, ")"));
